class SessionManager {
    public AuthenticatedSession createSession(SamlResponse samlResponse) {
        if (samlResponse == null) {
            throw new SamlProcessingException("SAML response is null");
        }
        if (samlResponse.getAssertions().isEmpty()) {
            throw new SamlProcessingException("SAML response contains no assertions");
        }

        SamlAssertion selectedAssertion = selectValidAssertion(samlResponse.getAssertions());
        if (selectedAssertion.getNameId() == null || selectedAssertion.getNameId().isBlank()) {
            throw new SamlProcessingException("Assertion does not contain a valid subject NameID");
        }

        AuthenticatedSession session = new AuthenticatedSession();
        session.setSessionId(UUID.randomUUID().toString());
        session.setPrincipal(selectedAssertion.getNameId());
        session.setAttributes(flattenAttributes(selectedAssertion.getAttributes()));
        session.setAuthenticatedAt(Instant.now());
        session.setExpiresAt(resolveExpiry(selectedAssertion));
        return session;
    }

    private SamlAssertion selectValidAssertion(List<SamlAssertion> assertions) {
        Instant now = Instant.now();
        for (SamlAssertion assertion : assertions) {
            if (assertion.getNotBefore() != null && now.isBefore(assertion.getNotBefore())) {
                continue;
            }
            if (assertion.getNotOnOrAfter() != null && !now.isBefore(assertion.getNotOnOrAfter())) {
                continue;
            }
            return assertion;
        }
        throw new SamlProcessingException("No valid assertion found for current time window");
    }

    private Instant resolveExpiry(SamlAssertion assertion) {
        if (assertion.getNotOnOrAfter() != null) {
            return assertion.getNotOnOrAfter();
        }
        return Instant.now().plusSeconds(3600);
    }

    private Map<String, Object> flattenAttributes(Map<String, List<String>> attributes) {
        Map<String, Object> result = new HashMap<>();
        for (Map.Entry<String, List<String>> entry : attributes.entrySet()) {
            List<String> values = entry.getValue();
            if (values == null || values.isEmpty()) {
                result.put(entry.getKey(), "");
            } else if (values.size() == 1) {
                result.put(entry.getKey(), values.get(0));
            } else {
                result.put(entry.getKey(), new ArrayList<>(values));
            }
        }
        return result;
    }
}

